#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

#define IDX(r, c, n) ((r) * (n) + (c))

__kernel void lud_diagonal(__global float *m,
                           __local float *shadow,
                           const int matrix_dim,
                           const int offset)
{
    (void)shadow;

    if (get_local_id(0) != 0) return;

    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = i; j < BLOCK_SIZE; j++) {
            float sum = m[IDX(offset + i, offset + j, matrix_dim)];
            for (int k = 0; k < i; k++) {
                sum -= m[IDX(offset + i, offset + k, matrix_dim)] *
                       m[IDX(offset + k, offset + j, matrix_dim)];
            }
            m[IDX(offset + i, offset + j, matrix_dim)] = sum;
        }

        float temp = 1.0f / m[IDX(offset + i, offset + i, matrix_dim)];
        for (int j = i + 1; j < BLOCK_SIZE; j++) {
            float sum = m[IDX(offset + j, offset + i, matrix_dim)];
            for (int k = 0; k < i; k++) {
                sum -= m[IDX(offset + j, offset + k, matrix_dim)] *
                       m[IDX(offset + k, offset + i, matrix_dim)];
            }
            m[IDX(offset + j, offset + i, matrix_dim)] = sum * temp;
        }
    }
}

__kernel void lud_perimeter(__global float *m,
                            __local float *dia,
                            __local float *peri_row,
                            __local float *peri_col,
                            const int matrix_dim,
                            const int offset)
{
    (void)dia;
    (void)peri_row;
    (void)peri_col;

    if (get_local_id(0) != 0) return;

    int chunks = (matrix_dim - offset) / BLOCK_SIZE - 1;
    int chunk_idx = (int)get_group_id(0);
    if (chunk_idx >= chunks) return;

    int i_global = offset;
    int j_global = offset + BLOCK_SIZE * (chunk_idx + 1);

    for (int j = 0; j < BLOCK_SIZE; j++) {
        for (int i = 0; i < BLOCK_SIZE; i++) {
            float sum = 0.0f;
            for (int k = 0; k < i; k++) {
                sum += m[IDX(i_global + i, offset + k, matrix_dim)] *
                       m[IDX(offset + k, j_global + j, matrix_dim)];
            }
            m[IDX(i_global + i, j_global + j, matrix_dim)] -= sum;
        }
    }

    i_global = offset + BLOCK_SIZE * (chunk_idx + 1);
    j_global = offset;

    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            float sum = 0.0f;
            for (int k = 0; k < j; k++) {
                sum += m[IDX(i_global + i, j_global + k, matrix_dim)] *
                       m[IDX(offset + k, offset + j, matrix_dim)];
            }
            float v = m[IDX(i_global + i, j_global + j, matrix_dim)];
            m[IDX(i_global + i, j_global + j, matrix_dim)] =
                (v - sum) / m[IDX(offset + j, offset + j, matrix_dim)];
        }
    }
}

__kernel void lud_internal(__global float *m,
                           __local float *peri_row,
                           __local float *peri_col,
                           const int matrix_dim,
                           const int offset)
{
    (void)peri_row;
    (void)peri_col;

    if (get_local_id(0) != 0 || get_local_id(1) != 0) return;

    int chunks = (matrix_dim - offset) / BLOCK_SIZE - 1;
    int bx = (int)get_group_id(0);
    int by = (int)get_group_id(1);
    if (bx >= chunks || by >= chunks) return;

    int i_global = offset + BLOCK_SIZE * (by + 1);
    int j_global = offset + BLOCK_SIZE * (bx + 1);

    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            float sum = 0.0f;
            for (int k = 0; k < BLOCK_SIZE; k++) {
                sum += m[IDX(i_global + i, offset + k, matrix_dim)] *
                       m[IDX(offset + k, j_global + j, matrix_dim)];
            }
            m[IDX(i_global + i, j_global + j, matrix_dim)] -= sum;
        }
    }
}
